import{_ as t,o as a,c as d,a2 as r}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"Random Image API และ Public Gallery","description":"","frontmatter":{},"headers":[],"relativePath":"th-TH/Other/random-image-api-and-public-gallery.md","filePath":"th-TH/Other/random-image-api-and-public-gallery.md","lastUpdated":1781962217000}'),i={name:"th-TH/Other/random-image-api-and-public-gallery.md"};function o(s,e,l,c,n,p){return a(),d("div",null,[...e[0]||(e[0]=[r(`<h1 id="random-image-api-และ-public-gallery" tabindex="-1">Random Image API และ Public Gallery <a class="header-anchor" href="#random-image-api-และ-public-gallery" aria-label="Permalink to &quot;Random Image API และ Public Gallery&quot;">​</a></h1><p>ทั้งสอง features ตั้งค่าได้ที่:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings</span></span></code></pre></div><h2 id="random-image-api" tabindex="-1">Random Image API <a class="header-anchor" href="#random-image-api" aria-label="Permalink to &quot;Random Image API&quot;">​</a></h2><p>Random Image API return random file หนึ่งรายการจาก selected directories เหมาะกับ site backgrounds, avatar rotation หรือ random image calls จาก external pages</p><p>หลัง enable แล้วใช้:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/random</span></span></code></pre></div><h2 id="random-image-api-settings" tabindex="-1">Random Image API Settings <a class="header-anchor" href="#random-image-api-settings" aria-label="Permalink to &quot;Random Image API Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Purpose</th></tr></thead><tbody><tr><td>Enable</td><td>เปิดหรือปิด endpoint <code>/random</code> เมื่อ disabled จะ forbidden</td></tr><tr><td>Directories</td><td>จำกัดว่า random API ใช้ directories ใดได้ Directories ที่ไม่อยู่ในนี้จะใช้กับ API ไม่ได้</td></tr><tr><td>Call demo</td><td>Generate random API links ที่ copy ได้โดยตรง</td></tr></tbody></table><p>เลือกได้หลาย directories เช่น ถ้า allow เฉพาะ <code>/landscape/</code> และ <code>/portrait/</code> random API จะเลือก files ได้เฉพาะจาก directories เหล่านั้นและ subdirectories</p><h2 id="random-image-api-parameters" tabindex="-1">Random Image API Parameters <a class="header-anchor" href="#random-image-api-parameters" aria-label="Permalink to &quot;Random Image API Parameters&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Parameter</th><th>Example</th><th>Purpose</th></tr></thead><tbody><tr><td><code>dir</code></td><td><code>/landscape/</code></td><td>ระบุ random directory</td></tr><tr><td><code>content</code></td><td><code>image</code></td><td>ระบุ media type ใช้ <code>image</code>, <code>video</code>, <code>audio</code> หรือ comma-separated combinations</td></tr><tr><td><code>orientation</code></td><td><code>auto</code></td><td>Filter image orientation ใช้ <code>portrait</code>, <code>landscape</code> หรือ <code>auto</code></td></tr><tr><td><code>type</code></td><td><code>url</code></td><td>Return format ถ้าว่างคือ redirect, <code>url</code> return plain text URL, <code>json</code> return JSON</td></tr><tr><td><code>origin</code></td><td><code>1</code></td><td>ใช้กับ <code>type=url</code> เพื่อ return full URL</td></tr><tr><td><code>age</code></td><td><code>all-ages,r12</code></td><td>Filter ตาม age rating</td></tr><tr><td><code>tag</code></td><td><code>wallpaper,sky</code></td><td>Return เฉพาะ files ที่มี tags เหล่านี้</td></tr><tr><td><code>ex</code></td><td><code>private</code></td><td>Exclude files ที่มี tags เหล่านี้</td></tr></tbody></table><h2 id="return-formats" tabindex="-1">Return Formats <a class="header-anchor" href="#return-formats" aria-label="Permalink to &quot;Return Formats&quot;">​</a></h2><p>ถ้าไม่มี <code>type</code> API จะ redirect ไปยัง random file URL โดยตรง</p><p>เมื่อ <code>type=url</code> จะ return text URL</p><p>เมื่อ <code>type=json</code> จะ return file information รวม file URL, file ID, file name, file type, tags, rating และ metadata ที่เกี่ยวข้อง</p><h2 id="access-rules" tabindex="-1">Access Rules <a class="header-anchor" href="#access-rules" aria-label="Permalink to &quot;Access Rules&quot;">​</a></h2><p>Random Image API ปฏิบัติตาม public access rules:</p><table tabindex="0"><thead><tr><th>Rule</th><th>Effect</th></tr></thead><tbody><tr><td>Directory restriction</td><td>เลือกได้เฉพาะ files ใน allowed directories</td></tr><tr><td>Blocklist</td><td>Blocklisted files ถูก exclude จาก random pool</td></tr><tr><td>Allowlist mode</td><td>เมื่อ enabled จะ return เฉพาะ files ที่ allowed สำหรับ public access</td></tr><tr><td>Age rating</td><td>R12, R16, R18 และ content คล้ายกันถูก filter ตาม current access mode</td></tr></tbody></table><p>ถ้าหลัง filtering ไม่มี file match API จะ return no matching result</p><h2 id="cache" tabindex="-1">Cache <a class="header-anchor" href="#cache" aria-label="Permalink to &quot;Cache&quot;">​</a></h2><p>Random Image API cache directory candidate pools เพื่อเพิ่ม speed</p><p>เมื่อ files เปลี่ยน ImgBed จะ update directory cache version และ requests ภายหลังจะ rebuild candidate pool Empty directories จะถูก cache สั้น ๆ เพื่อเลี่ยง repeated queries</p><h2 id="public-gallery" tabindex="-1">Public Gallery <a class="header-anchor" href="#public-gallery" aria-label="Permalink to &quot;Public Gallery&quot;">​</a></h2><p>Public gallery ให้หน้า public browsing แบบ read-only สำหรับ directories ที่คุณอนุญาตให้ visitors เห็น</p><p>หลัง enable แล้ว visitors เปิดได้ที่:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/browse/directory-name</span></span></code></pre></div><h2 id="public-gallery-settings" tabindex="-1">Public Gallery Settings <a class="header-anchor" href="#public-gallery-settings" aria-label="Permalink to &quot;Public Gallery Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Purpose</th></tr></thead><tbody><tr><td>Enable</td><td>เปิดหรือปิด public gallery เมื่อ disabled visitors จะ browse ไม่ได้</td></tr><tr><td>Image loading mode</td><td>ควบคุมว่า previews ใช้ original images หรือ thumbnails</td></tr><tr><td>Open directories</td><td>กำหนดว่า visitors access directories ใดได้</td></tr></tbody></table><h2 id="image-loading-mode" tabindex="-1">Image Loading Mode <a class="header-anchor" href="#image-loading-mode" aria-label="Permalink to &quot;Image Loading Mode&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Mode</th><th>Purpose</th></tr></thead><tbody><tr><td>Original</td><td>Visitor page load original files โดยตรง</td></tr><tr><td>Thumbnail</td><td>Visitor page prefer thumbnails เพื่อ loading ที่เร็วขึ้น</td></tr></tbody></table><h2 id="open-directories" tabindex="-1">Open Directories <a class="header-anchor" href="#open-directories" aria-label="Permalink to &quot;Open Directories&quot;">​</a></h2><p>Open directories ตัดสินว่า visitors เห็นอะไรได้</p><p>Example:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/1/,/2/,/landscape/,/portrait/</span></span></code></pre></div><p>Visitors จะ access ได้ที่:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/browse/1</span></span>
<span class="line"><span>https://your-domain.com/browse/2</span></span>
<span class="line"><span>https://your-domain.com/browse/landscape</span></span>
<span class="line"><span>https://your-domain.com/browse/portrait</span></span></code></pre></div><p>Subdirectories ก็เปิดได้ เช่น <code>/2026/lucky/</code> Visitors จะถูก block จาก directories ที่ไม่ได้ open</p><h2 id="public-gallery-features" tabindex="-1">Public Gallery Features <a class="header-anchor" href="#public-gallery-features" aria-label="Permalink to &quot;Public Gallery Features&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td>Browse directories</td><td>ดู files และ subdirectories ใน open directories</td></tr><tr><td>Search</td><td>Search ด้วย file name, file ID หรือ tags</td></tr><tr><td>Type filter</td><td>Filter images, videos, audio หรือ other files</td></tr><tr><td>Tag filter</td><td>Include หรือ exclude selected tags</td></tr><tr><td>Orientation filter</td><td>Filter landscape หรือ portrait images</td></tr><tr><td>Time filter</td><td>Filter ตาม upload time range</td></tr><tr><td>Extension filter</td><td>Filter ตาม file extension</td></tr><tr><td>Copy link</td><td>Copy file access links</td></tr><tr><td>Media preview</td><td>ดูหรือเล่น images, videos และ audio บน visitor page</td></tr></tbody></table><h2 id="public-gallery-access-rules" tabindex="-1">Public Gallery Access Rules <a class="header-anchor" href="#public-gallery-access-rules" aria-label="Permalink to &quot;Public Gallery Access Rules&quot;">​</a></h2><p>Public gallery ก็ปฏิบัติตาม public access rules:</p><table tabindex="0"><thead><tr><th>Rule</th><th>Effect</th></tr></thead><tbody><tr><td>Open directories</td><td>แสดงเฉพาะ allowed directories</td></tr><tr><td>Access mode</td><td>Content ถูก filter ตาม current age-rating access mode</td></tr><tr><td>Allowlist mode</td><td>เมื่อ enabled จะแสดงเฉพาะ files ที่ allowed สำหรับ public access</td></tr><tr><td>Blocklist</td><td>Blocklisted files ถูกซ่อน</td></tr></tbody></table>`,43)])])}const m=t(i,[["render",o]]);export{u as __pageData,m as default};
